import pygame
import sys
import time
import random

pygame.init()

white = (255, 255, 255)
black = (0, 0, 0)
red = (255, 0, 0)
green = (0, 255, 0)

size = (800, 600)
screen = pygame.display.set_mode(size)
pygame.display.set_caption("Snake Game")

clock = pygame.time.Clock()

class SnakeGame:
    def __init__(self):
        self.snake_list = [(200, 200), (220, 200), (240, 200)]
        self.direction = "right"
        self.food = self.generate_food()

    def generate_food(self):
        return (random.randint(0, size[0] - 20) // 20 * 20, random.randint(0, size[1] - 20) // 20 * 20)

    def update(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_UP and self.direction != "down":
                    self.direction = "up"
                elif event.key == pygame.K_DOWN and self.direction != "up":
                    self.direction = "down"
                elif event.key == pygame.K_LEFT and self.direction != "right":
                    self.direction = "left"
                elif event.key == pygame.K_RIGHT and self.direction != "left":
                    self.direction = "right"

        head = self.snake_list[-1]
        if self.direction == "up":
            new_head = (head[0], head[1] - 20)
        elif self.direction == "down":
            new_head = (head[0], head[1] + 20)
        elif self.direction == "left":
            new_head = (head[0] - 20, head[1])
        elif self.direction == "right":
            new_head = (head[0] + 20, head[1])

        self.snake_list.append(new_head)

        if self.snake_list[-1] == self.food:
            self.food = self.generate_food()
        else:
            self.snake_list.pop(0)

        if (self.snake_list[-1][0] < 0 or self.snake_list[-1][0] >= size[0] or
            self.snake_list[-1][1] < 0 or self.snake_list[-1][1] >= size[1] or
            self.snake_list[-1] in self.snake_list[:-1]):
            pygame.quit()
            sys.exit()

    def draw(self):
        screen.fill(black)
        for pos in self.snake_list:
            pygame.draw.rect(screen, green, (pos[0], pos[1], 20, 20))
        pygame.draw.rect(screen, red, (self.food[0], self.food[1], 20, 20))
        pygame.display.flip()

game = SnakeGame()
while True:
    game.update()
    game.draw()
    clock.tick(10)

import pygame
import sys
import random

pygame.init()

width, height = 800, 600
screen = pygame.display.set_mode((width, height))
pygame.display.set_caption('Snake Game')
clock = pygame.time.Clock()

font = pygame.font.Font(None, 36)

class SnakeGame:
    def __init__(self):
        self.snake = [(200, 200), (220, 200), (240, 200)]
        self.direction = 'right'
        self.food = self.generate_food()

    def generate_food(self):
        while True:
            x = random.randint(0, width - 20) // 20 * 20
            y = random.randint(0, height - 20) // 20 * 20
            food = (x, y)
            if food not in self.snake:
                return food

    def play(self):
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    sys.exit()
                elif event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_UP and self.direction != 'down':
                        self.direction = 'up'
                    elif event.key == pygame.K_DOWN and self.direction != 'up':
                        self.direction = 'down'
                    elif event.key == pygame.K_LEFT and self.direction != 'right':
                        self.direction = 'left'
                    elif event.key == pygame.K_RIGHT and self.direction != 'left':
                        self.direction = 'right'

            head = self.snake[-1]
            if self.direction == 'up':
                new_head = (head[0], head[1] - 20)
            elif self.direction == 'down':
                new_head = (head[0], head[1] + 20)
            elif self.direction == 'left':
                new_head = (head[0] - 20, head[1])
            elif self.direction == 'right':
                new_head = (head[0] + 20, head[1])

            if (new_head[0] < 0 or new_head[0] >= width or
                    new_head[1] < 0 or new_head[1] >= height or
                    new_head in self.snake):
                text = font.render('Game Over', True, (255, 255, 255))
                screen.fill((0, 0, 0))
                screen.blit(text, (width // 2 - 50, height // 2 - 18))
                pygame.display.flip()
                pygame.time.wait(2000)
                break

            self.snake.append(new_head)
            if self.food == new_head:
                self.food = self.generate_food()
            else:
                self.snake.pop(0)

            screen.fill((0, 0, 0))
            for pos in self.snake:
                pygame.draw.rect(screen, (0, 255, 0), (pos[0], pos[1], 20, 20))
            pygame.draw.rect(screen, (255, 0, 0), (self.food[0], self.food[1], 20, 20))
            pygame.display.flip()
            clock.tick(10)

game = SnakeGame()
game.play()

import pygame
import sys
import time
import random

pygame.init()

white = (255, 255, 255)
black = (0, 0, 0)
red = (255, 0, 0)
green = (0, 255, 0)
blue = (0, 0, 255)

display_width = 800
display_height = 600
game_display = pygame.display.set_mode((display_width, display_height))
pygame.display.set_caption('Snake Game')

clock = pygame.time.Clock()

snake_list = []
snake_length = 1
snake_block = 20
snake_speed = 15

font_style = pygame.font.SysFont("bahnschrift", 25)
score_font = pygame.font.SysFont("comicsansms", 35)

def your_score(score):
    value = score_font.render("Your Score: " + str(score), True, black)
    game_display.blit(value, [0, 0])

def our_snake(snake_block, snake_list):
    for x in snake_list:
        pygame.draw.rect(game_display, black, [x[0], x[1], snake_block, snake_block])

def message(msg, color):
    mesg = font_style.render(msg, True, color)
    game_display.blit(mesg, [display_width / 6, display_height / 3])

def game_loop():
    global snake_length
    global snake_list
    global snake_speed
    direction = 'right'
    snake_list = []
    snake_head = [display_width / 2, display_height / 2]
    snake_list.append(snake_head)
    foodx = round(random.randrange(0, display_width - snake_block) / 20.0) * 20.0
    foody = round(random.randrange(0, display_height - snake_block) / 20.0) * 20.0

    while True:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    direction = 'left'
                elif event.key == pygame.K_RIGHT:
                    direction = 'right'
                elif event.key == pygame.K_UP:
                    direction = 'up'
                elif event.key == pygame.K_DOWN:
                    direction = 'down'

        if direction == 'up':
            snake_head[1] -= snake_block
        elif direction == 'down':
            snake_head[1] += snake_block
        elif direction == 'left':
            snake_head[0] -= snake_block
        elif direction == 'right':
            snake_head[0] += snake_block

        game_display.fill(white)

        pygame.draw.rect(game_display, green, [foodx, foody, snake_block, snake_block])
        snake_head_list = []
        snake_head_list.append(snake_head)
        our_snake(snake_block, snake_head_list)

        if snake_head in snake_list[:-1]:
            message("You lost! Press C-Play Again or Q-Quit", red)
            pygame.display.update()
            for event in pygame.event.get():
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_c:
                        game_loop()
                    elif event.key == pygame.K_q:
                        pygame.quit()
                        sys.exit()

        if snake_head[0] < 0 or snake_head[0] >= display_width:
            message("You lost! Press C-Play Again or Q-Quit", red)
            pygame.display.update()
            for event in pygame.event.get():
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_c:
                        game_loop()
                    elif event.key == pygame.K_q:
                        pygame.quit()
                        sys.exit()
        if snake_head[1] < 0 or snake_head[1] >= display_height:
            message("You lost! Press C-Play Again or Q-Quit", red)
            pygame.display.update()
            for event in pygame.event.get():
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_c:
                        game_loop()
                    elif event.key == pygame.K_q:
                        pygame.quit()
                        sys.exit()

        snake_list.append(snake_head)
        if len(snake_list) > snake_length:
            del snake_list[0]

        if snake_head == [foodx, foody]:
            foodx = round(random.randrange(0, display_width - snake_block) / 20.0) * 20.0
            foody = round(random.randrange(0, display_height - snake_block) / 20.0) * 20.0
            snake_length += 1
            snake_speed += 0.5

        your_score(snake_length - 1)
        our_snake(snake_block, snake_list)
        pygame.display.update()
        clock.tick(snake_speed)

game_loop()

