import pygame
import sys
import time
import random

pygame.init()

width, height = 800, 600
screen = pygame.display.set_mode((width, height))
pygame.display.set_caption('Snake Game')
clock = pygame.time.Clock()

snake_pos = [100, 50]
snake_body = [[100, 50], [90, 50], [80, 50], [70, 50]]
food_pos = [random.randrange(1, (width//10)) * 10, random.randrange(1, (height//10)) * 10]
food_spawn = True
direction = 'RIGHT'
score = 0

while True:
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            pygame.quit()
            sys.exit()
        elif event.type == pygame.KEYDOWN:
            if event.key == pygame.K_UP and direction != 'DOWN':
                direction = 'UP'
            elif event.key == pygame.K_DOWN and direction != 'UP':
                direction = 'DOWN'
            elif event.key == pygame.K_LEFT and direction != 'RIGHT':
                direction = 'LEFT'
            elif event.key == pygame.K_RIGHT and direction != 'LEFT':
                direction = 'RIGHT'

    if direction == 'UP':
        snake_pos[1] -= 10
    elif direction == 'DOWN':
        snake_pos[1] += 10
    elif direction == 'LEFT':
        snake_pos[0] -= 10
    elif direction == 'RIGHT':
        snake_pos[0] += 10

    snake_body.insert(0, list(snake_pos))
    if snake_pos == food_pos:
        score += 1
        food_spawn = False
    else:
        snake_body.pop()

    if food_spawn == False:
        food_pos = [random.randrange(1, (width//10)) * 10, random.randrange(1, (height//10)) * 10]
        food_spawn = True

    if (snake_pos[0] < 0 or snake_pos[0] > width-10) or (snake_pos[1] < 0 or snake_pos[1] > height-10):
        print('Game Over')
        print('Your score is: ', score)
        pygame.quit()
        sys.exit()

    for block in snake_body[1:]:
        if snake_pos == block:
            print('Game Over')
            print('Your score is: ', score)
            pygame.quit()
            sys.exit()

    screen.fill((0, 0, 0))
    for pos in snake_body:
        pygame.draw.rect(screen, (0, 255, 0), pygame.Rect(pos[0], pos[1], 10, 10))
    pygame.draw.rect(screen, (255, 0, 0), pygame.Rect(food_pos[0], food_pos[1], 10, 10))
    pygame.display.update()
    clock.tick(10)

import pygame
import sys
import time
import random

pygame.init()

width = 800
height = 600
block_size = 20
fps = 10

screen = pygame.display.set_mode((width, height))
pygame.display.set_caption('Snake Game')
clock = pygame.time.Clock()

class Snake:
    def __init__(self):
        self.body = [(200, 200), (220, 200), (240, 200)]
        self.direction = 'right'

    def move(self):
        head = self.body[-1]
        if self.direction == 'right':
            new_head = (head[0] + block_size, head[1])
        elif self.direction == 'left':
            new_head = (head[0] - block_size, head[1])
        elif self.direction == 'up':
            new_head = (head[0], head[1] - block_size)
        elif self.direction == 'down':
            new_head = (head[0], head[1] + block_size)
        self.body.append(new_head)
        self.body.pop(0)

    def grow(self):
        self.body.insert(0, self.body[0])

class Food:
    def __init__(self):
        self.position = (random.randint(0, width - block_size) // block_size * block_size, 
                         random.randint(0, height - block_size) // block_size * block_size)

    def new_food(self):
        self.position = (random.randint(0, width - block_size) // block_size * block_size, 
                         random.randint(0, height - block_size) // block_size * block_size)

def draw_snake(snake):
    for pos in snake.body:
        pygame.draw.rect(screen, (0, 255, 0), (pos[0], pos[1], block_size, block_size))

def draw_food(food):
    pygame.draw.rect(screen, (255, 0, 0), (food.position[0], food.position[1], block_size, block_size))

def main():
    snake = Snake()
    food = Food()
    while True:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_UP and snake.direction != 'down':
                    snake.direction = 'up'
                elif event.key == pygame.K_DOWN and snake.direction != 'up':
                    snake.direction = 'down'
                elif event.key == pygame.K_LEFT and snake.direction != 'right':
                    snake.direction = 'left'
                elif event.key == pygame.K_RIGHT and snake.direction != 'left':
                    snake.direction = 'right'

        screen.fill((0, 0, 0))
        snake.move()
        draw_snake(snake)
        draw_food(food)

        if (snake.body[-1][0] < 0 or snake.body[-1][0] >= width or 
            snake.body[-1][1] < 0 or snake.body[-1][1] >= height or 
            snake.body[-1] in snake.body[:-1]):
            print('Game Over')
            pygame.quit()
            sys.exit()

        if snake.body[-1] == food.position:
            snake.grow()
            food.new_food()

        pygame.display.update()
        clock.tick(fps)

if __name__ == '__main__':
    main()

