        pygame.draw.rect(screen, red, pygame.Rect(self.apple[0], self.apple[1], 20, 20))

    def update_snake(self):
        head = self.snake_list[-1]
        if self.direction == 'right':
            new_head = (head[0] + 20, head[1])
        elif self.direction == 'left':
            new_head = (head[0] - 20, head[1])
        elif self.direction == 'up':
            new_head = (head[0], head[1] - 20)
        elif self.direction == 'down':
            new_head = (head[0], head[1] + 20)

        self.snake_list.append(new_head)
        if self.snake_list[-1] == self.apple:
            self.apple = self.generate_apple()
        else:
            self.snake_list.pop(0)

    def check_collision(self):
        head = self.snake_list[-1]
        if head[0] < 0 or head[0] >= size[0] or head[1] < 0 or head[1] >= size[1]:
            return True
        if head in self.snake_list[:-1]:
            return True
        return False

