class Snake:
    def __init__(self):
        self.body = [(200, 200), (220, 200), (240, 200)]
        self.direction = "right"

    def move(self):
        if self.direction == "right":
            new_head = (self.body[-1][0] + 20, self.body[-1][1])
        elif self.direction == "left":
            new_head = (self.body[-1][0] - 20, self.body[-1][1])
        elif self.direction == "up":
            new_head = (self.body[-1][0], self.body[-1][1] - 20)
        elif self.direction == "down":
            new_head = (self.body[-1][0], self.body[-1][1] + 20)
        self.body.append(new_head)
        self.body.pop(0)

    def grow(self):
        self.body.insert(0, self.body[0])

class Food:
    def __init__(self):
        self.position = (random.randint(0, width - 20) // 20 * 20, random.randint(0, height - 20) // 20 * 20)

    def new_food(self):
        self.position = (random.randint(0, width - 20) // 20 * 20, random.randint(0, height - 20) // 20 * 20)

def draw_text(text, font_size, color, x, y):
    font = pygame.font.SysFont("Arial", font_size)
    text_surface = font.render(text, True, color)
    screen.blit(text_surface, (x, y))

def main():
    snake = Snake()
    food = Food()
    score = 0
    while True:
        for event in pygame.event.get():
